const API_BASE = 'https://emkay-backend-9wt2.onrender.com';
const LOGO = 'data:image/jpeg;base64,';

// ── SPLASH ──────────────────────────────────────────────────────
document.addEventListener('click', function(e) {
  var wrap = document.querySelector('.lang-wrap');
  if (wrap && !wrap.contains(e.target)) wrap.classList.remove('open');
});

window.addEventListener('load', () => {
  const saved = localStorage.getItem('emkay-theme') || 'light';
  const mode = saved === 'dark' ? 'light' : saved; // always default to light
  applyTheme(mode);
  setTimeout(showPushPrompt, 5000);
  initChat();
});

// ── THEME ────────────────────────────────────────────────────────
const icon = document.getElementById('theme-icon');
function applyTheme(mode) {
  document.body.classList.toggle('light', mode === 'light');
  icon.textContent = mode === 'light' ? '☀️' : '🌙';
}
function toggleTheme() {
  const isLight = document.body.classList.contains('light');
  const m = isLight ? 'dark' : 'light';
  localStorage.setItem('emkay-theme', m);
  applyTheme(m);
}

// ── CONTACT FORM ─────────────────────────────────────────────────
async function submitForm(e) {
  e.preventDefault();
  const btn = document.getElementById('form-btn');
  const msg = document.getElementById('form-msg');
  const first = document.getElementById('f-first').value.trim();
  const last  = document.getElementById('f-last').value.trim();
  const email = document.getElementById('f-email').value.trim();
  const phone = document.getElementById('f-phone').value.trim();
  const service = document.getElementById('f-service').value;
  const message = document.getElementById('f-message').value.trim();
  if (!first || !last || !email || !message) { showMsg('Please fill in all required fields.','error'); return; }
  btn.disabled = true; btn.textContent = 'Sending…'; msg.style.display = 'none';
  try {
    const res = await fetch(`${API_BASE}/api/contact`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        first_name: first,
        last_name: last,
        email: email,
        phone: phone || null,
        service: service || null,
        message: message,
      }),
    });
    if (res.ok) {
      showMsg('✓ Your message has been sent! We will be in touch shortly.','success');
      document.querySelectorAll('#contact input,#contact textarea').forEach(el=>el.value='');
      document.getElementById('f-service').selectedIndex=0;
    } else {
      const err = await res.json();
      let errMsg = 'Something went wrong. Please try again.';
      if (err.detail) errMsg = typeof err.detail==='string' ? err.detail : err.detail.map(e=>e.msg).join('. ');
      showMsg(errMsg,'error');
    }
  } catch { showMsg('Unable to reach the server. Please call us directly.','error'); }
  btn.disabled = false; btn.textContent = 'Send Message →';
}
function showMsg(text,type) {
  const el = document.getElementById('form-msg');
  el.textContent = text; el.className = 'form-msg '+type; el.style.display = 'block';
  el.scrollIntoView({behavior:'smooth',block:'nearest'});
}

// ── PUSH NOTIFICATIONS ───────────────────────────────────────────
function showPushPrompt() {
  if (Notification.permission === 'default') document.getElementById('push-prompt').classList.add('show');
}
function allowPush() {
  Notification.requestPermission().then(p => {
    if (p === 'granted') new Notification('Emkay Surveys', {body:'You\'ll now receive updates from us. Thank you!', icon: LOGO});
  });
  dismissPush();
}
function dismissPush() { document.getElementById('push-prompt').classList.remove('show'); }

// ── SUGGESTION BOX ───────────────────────────────────────────────
function toggleSuggest() { document.getElementById('suggest-panel').classList.toggle('open'); }
async function submitSuggestion() {
  const text = document.getElementById('sug-text').value.trim();
  const name = document.getElementById('sug-name').value.trim();
  if (!text) return;
  try {
    await fetch(`${API_BASE}/api/suggestion`, {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({name: name||'Anonymous', suggestion: text})
    });
  } catch {}
  document.getElementById('sug-text').value = '';
  document.getElementById('suggest-done-txt').style.display = 'block';
  setTimeout(() => {
    document.getElementById('suggest-done-txt').style.display = 'none';
    document.getElementById('suggest-panel').classList.remove('open');
  }, 2500);
}

// ── SCHEDULE A CALL ──────────────────────────────────────────────
async function submitSchedule() {
  const name  = document.getElementById('sc-name').value.trim();
  const phone = document.getElementById('sc-phone').value.trim();
  const date  = document.getElementById('sc-date').value;
  const time  = document.getElementById('sc-time').value;
  const topic = document.getElementById('sc-topic').value;
  if (!name || !phone || !date || !time) { alert('Please fill in all fields.'); return; }
  try {
    await fetch(`${API_BASE}/api/schedule`, {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({name, phone, date, time, topic})
    });
  } catch {}
  document.getElementById('schedule-form').style.display = 'none';
  document.getElementById('schedule-done').style.display = 'block';
  setTimeout(() => {
    document.getElementById('schedule-overlay').classList.remove('open');
    document.getElementById('schedule-form').style.display = 'block';
    document.getElementById('schedule-done').style.display = 'none';
    ['sc-name','sc-phone','sc-date','sc-time'].forEach(id => document.getElementById(id).value = '');
    document.getElementById('sc-topic').selectedIndex = 0;
  }, 3000);
}

