// ══════════════════════════════════════════════════════════════════════════
// EMKAY SMART NLP ENGINE  (no external API — 100% in-browser)
// Features: auto language detection · fuzzy matching · stemming ·
//           TF-IDF weighting · context memory · multilingual replies
// ══════════════════════════════════════════════════════════════════════════

// ── 1. LANGUAGE DETECTION ────────────────────────────────────────────────
// Signature words that strongly identify a language
const LANG_SIGNATURES = {
  ha: ['sannu','ina','yaya','menene','yaushe','nawa','don','ƙ','ɓ','ɗ','aiki','gida','kai','shi','ita','mu','su','kuɗi','waya','miye','babu','sai','da','na','ga','ya','ta','ko','amma','lokaci','ofishi','ayyuka','gini','ƙasa'],
  yo: ['bawo','ẹ','ṣe','ọ','ni','pẹlu','jẹ','tabi','iṣẹ','ile','owo','orukọ','ilẹ','ẹka','foonu','olubasọrọ','ibiti','kini','ṣii','tiipa','idiyè','igba'],
  ig: ['gịnị','kedu','ọ','bụ','daalụ','ndewo','ebe','onye','ihe','ọrụ','ego','oge','ụlọ','ala','mmadụ','ozi','nọmba','ekwentị'],
  ar: ['كيف','ما','متى','أين','من','هل','نعم','لا','شكرا','مرحبا','خدمات','مكتب','سعر','هاتف','بريد','موعد','معادن','بناء'],
  fr: ['bonjour','merci','comment','quoi','quand','où','qui','pourquoi','oui','non','services','bureau','heure','prix','téléphone','adresse'],
  es: ['hola','gracias','cómo','qué','cuándo','dónde','quién','sí','no','servicios','oficina','precio','teléfono'],
  pt: ['olá','obrigado','como','que','quando','onde','quem','sim','não','serviços','escritório','preço','telefone'],
  de: ['hallo','danke','wie','was','wann','wo','wer','ja','nein','dienste','büro','preis','telefon'],
  sw: ['habari','asante','jinsi','nini','lini','wapi','nani','ndiyo','hapana','huduma','ofisi','bei','simu'],
  zh: ['你好','谢谢','怎么','什么','时候','哪里','谁','是','不','服务','办公室','价格','电话'],
  en: ['hello','hi','hey','thanks','how','what','when','where','who','yes','no','services','office','price','phone','email','hours','location']
};

function detectLang(text) {
  const t = text.toLowerCase();
  // Check for Arabic/CJK script first (unambiguous)
  if (/[\u0600-\u06FF]/.test(text)) return 'ar';
  if (/[\u4E00-\u9FFF]/.test(text)) return 'zh';
  let scores = {};
  for (const [lang, sigs] of Object.entries(LANG_SIGNATURES)) {
    scores[lang] = sigs.filter(s => t.includes(s)).length;
  }
  // Special Hausa letter boost
  if (/[ƙɓɗ]/i.test(text)) scores.ha = (scores.ha||0) + 3;
  // Yoruba diacritic boost
  if (/[ẹọṣ]/i.test(text)) scores.yo = (scores.yo||0) + 3;
  // Igbo diacritic boost
  if (/[ụị]/i.test(text)) scores.ig = (scores.ig||0) + 3;
  const best = Object.entries(scores).sort((a,b)=>b[1]-a[1])[0];
  return (best && best[1] > 0) ? best[0] : null; // null = defer to currentLang
}

// ── 2. STEMMER — strips common suffixes for major languages ──────────────
function stem(word) {
  // English
  word = word.replace(/(?:ing|tion|tions|ed|es|er|ly|ness|ment|ful|ous|ive|able|ible|al|ic|ical)$/,'');
  // Hausa inflections: -nku -nka -nki -nsa -nta -mu -ku -ta -su
  word = word.replace(/(?:nku|nka|nki|nsa|nta|unku|n)$/,'');
  // Yoruba: -ni -le -wa -pe
  word = word.replace(/(?:ni|le|wa|pe)$/,'');
  // Swahili: -nia -ana -wa -ka -ku
  word = word.replace(/(?:nia|ana|wa|ka|ku)$/,'');
  // Minimum length 3
  return word.length >= 3 ? word : word + '_';
}

// ── 3. FUZZY MATCH — Levenshtein for short words ─────────────────────────
function levenshtein(a, b) {
  if (Math.abs(a.length - b.length) > 3) return 99;
  const m = [], al = a.length, bl = b.length;
  for (let i=0; i<=al; i++) { m[i]=[i]; }
  for (let j=0; j<=bl; j++) { m[0][j]=j; }
  for (let i=1; i<=al; i++)
    for (let j=1; j<=bl; j++)
      m[i][j] = a[i-1]===b[j-1] ? m[i-1][j-1] : 1+Math.min(m[i-1][j],m[i][j-1],m[i-1][j-1]);
  return m[al][bl];
}

function fuzzyIncludes(haystack, needle) {
  if (haystack.includes(needle)) return true;
  if (needle.length < 4) return false; // skip fuzzy for short words
  const words = haystack.split(/\s+/);
  const needleStemmed = stem(needle);
  for (const w of words) {
    if (stem(w) === needleStemmed) return true;
    const thresh = needle.length <= 5 ? 1 : needle.length <= 8 ? 2 : 3;
    if (levenshtein(w, needle) <= thresh) return true;
  }
  return false;
}

