async function sendChat() {
  const input = document.getElementById('chat-input');
  const text = input.value.trim();
  if (!text) return;
  input.value = '';
  addUserMsg(text);

  if (humanMode) {
    await handleHumanCapture(text);
    return;
  }

  showTyping();
  setTimeout(() => {
    hideTyping();
    const reply = emkayBot(text);
    addBotMsg(reply);
  }, 600);
}

