let firebaseApp, firebaseDb, liveSessionId, liveSessionRef, liveMsgListener;

async function initFirebase() {
  if (firebaseApp) return;
  const { initializeApp } = await import('https://www.gstatic.com/firebasejs/10.12.0/firebase-app.js');
  const { getDatabase, ref, push, onValue, update, off } = await import('https://www.gstatic.com/firebasejs/10.12.0/firebase-database.js');
  // 🔧 REPLACE with your Firebase config
  const cfg = {
    apiKey: "AIzaSyCP1uB8LDKIOaFUuk6IxIkX9Sh9IWFeE6M",
    authDomain: "emkay-d4b3e.firebaseapp.com",
    databaseURL: "https://emkay-d4b3e-default-rtdb.firebaseio.com",
    projectId: "emkay-d4b3e",
    storageBucket: "emkay-d4b3e.firebasestorage.app",
    messagingSenderId: "917852562644",
    appId: "1:917852562644:web:3578326897ac6c6ecd0741"
  };
  firebaseApp = initializeApp(cfg, 'visitor-chat');
  firebaseDb = getDatabase(firebaseApp);
  window._fbRef = ref;
  window._fbPush = push;
  window._fbOnValue = onValue;
  window._fbUpdate = update;
  window._fbOff = off;
}

async function startLiveSession(visitorName, phone, enquiry) {
  await initFirebase();
  const { ref, push, onValue, update } = { ref: window._fbRef, push: window._fbPush, onValue: window._fbOnValue, update: window._fbUpdate };
  const sessionsRef = ref(firebaseDb, 'livechats');
  const sessionData = {
    visitorName, phone, enquiry,
    status: 'waiting',
    createdAt: Date.now(),
    updatedAt: Date.now(),
    adminUnread: true,
    visitorUnread: false
  };
  const newSession = await push(sessionsRef, sessionData);
  liveSessionId = newSession.key;
  liveSessionRef = ref(firebaseDb, `livechats/${liveSessionId}`);

  // Add opening message from visitor
  const msgsRef = ref(firebaseDb, `livechats/${liveSessionId}/messages`);
  await push(msgsRef, { sender: 'user', senderName: visitorName, text: enquiry, ts: Date.now() });

  // Listen for admin replies
  const msgsRefListen = ref(firebaseDb, `livechats/${liveSessionId}/messages`);
  let knownKeys = new Set();
  liveMsgListener = onValue(msgsRefListen, snap => {
    const data = snap.val();
    if (!data) return;
    Object.entries(data).forEach(([key, msg]) => {
      if (!knownKeys.has(key)) {
        knownKeys.add(key);
        if (msg.sender === 'admin') {
          addAdminMsg(msg.text);
          update(liveSessionRef, { visitorUnread: false });
        } else if (msg.sender === 'system' && msg.text === 'SESSION_ENDED') {
          // Admin ended the session — notify visitor
          humanMode = false; humanStep = 0;
          const endedMsg = {
            en: `🔴 This chat session has been ended by our team.\n\nThank you for contacting Emkay Surveys! If you need further assistance, feel free to start a new chat or reach us at:\n\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            ha: `🔴 Tattaunawar ta ƙare.\n\nNa gode da sadarwa da Emkay Surveys! Zaka iya tuntuɓarmu a:\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            fr: `🔴 Cette session de chat a été terminée par notre équipe.\n\nMerci de nous avoir contactés! Pour toute aide supplémentaire:\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            yo: `🔴 Ẹgbẹ wa ti pari iwiregbe yii.\n\nE dupe fun ibasọrọ pẹlu Emkay Surveys!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            ig: `🔴 Ndị otu anyị mechiri mkparịta ụka a.\n\nDaalụ maka ịkpọtụrụ Emkay Surveys!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            es: `🔴 Esta sesión ha sido finalizada por nuestro equipo.\n\n¡Gracias por contactarnos!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            pt: `🔴 Esta sessão foi encerrada pela nossa equipe.\n\nObrigado por nos contactar!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            de: `🔴 Diese Sitzung wurde von unserem Team beendet.\n\nDanke für Ihre Kontaktaufnahme!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            sw: `🔴 Kikao hiki kimekamilishwa na timu yetu.\n\nAsante kwa kuwasiliana na Emkay Surveys!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            zh: `🔴 此聊天会话已由我们的团队结束。\n\n感谢您联系Emkay Surveys！\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`,
            ar: `🔴 تم إنهاء هذه الجلسة من قِبَل فريقنا.\n\nشكراً لتواصلك مع Emkay Surveys!\n📞 +234 806 077 2573\n📧 Emkaysurveys@gmail.com`
          };
          addBotMsg(endedMsg[currentLang] || endedMsg.en);
          document.getElementById('chat-status').textContent = (T[currentLang]||T.en)['chat-session-ended-status'] || '🔴 Session ended';
          // Disable input so visitor can't keep typing into a closed session
          const input = document.getElementById('chat-input');
          if (input) { input.disabled = true; input.placeholder = (T[currentLang]||T.en)['chat-session-ended-placeholder'] || 'Session ended — start a new chat to continue'; }
          const sendBtn = document.querySelector('.chat-send-btn');
          if (sendBtn) sendBtn.disabled = true;
          // Show the human button again so they can start a new session
          const humanBtn = document.getElementById('chat-human-btn');
          if (humanBtn) { humanBtn.style.display = ''; humanBtn.textContent = (T[currentLang]||T.en)['chat-start-new-session-btn'] || '🔄 Start new session'; }
        }
      }
    });
  });
}

function addAdminMsg(text) {
  const msgs = document.getElementById('chat-msgs');
  const div = document.createElement('div');
  div.className = 'msg bot';
  div.innerHTML = `<strong style="color:var(--gold-light);font-size:11px;display:block;margin-bottom:4px;">👤 Emkay Support</strong>${text.replace(/\n/g,'<br>')}`;
  msgs.appendChild(div);
  msgs.scrollTop = msgs.scrollHeight;
  document.getElementById('chat-status').textContent = '🟢 Agent replied';
}

async function sendLiveMessage(text) {
  if (!liveSessionId) return;
  await initFirebase();
  const msgsRef = window._fbRef(firebaseDb, `livechats/${liveSessionId}/messages`);
  await window._fbPush(msgsRef, { sender: 'user', senderName: humanName || 'Visitor', text, ts: Date.now() });
  await window._fbUpdate(liveSessionRef, { adminUnread: true, updatedAt: Date.now() });
}

