// ── PROJECT SLIDER + ACCORDION ──────────────────────────────────
function toggleProject(card) {
  var allCards = document.querySelectorAll('.project-card');
  allCards.forEach(function(c) { if (c !== card) c.classList.remove('open'); });
  card.classList.toggle('open');
}

function updateDesc(card, idx) {
  var descs = card.querySelectorAll('.proj-desc-slides .project-desc');
  descs.forEach(function(d, i) { d.classList.toggle('active-desc', i === idx); });
}

function getSlider(btn) { return btn.closest('.proj-slider'); }

function slideProj(btn, dir) {
  var slider = getSlider(btn);
  var card = slider.closest('.project-card');
  var slides = slider.querySelector('.proj-slides');
  var dots = slider.querySelectorAll('.proj-dot');
  var total = slides.children.length;
  var current = parseInt(slides.dataset.current || 0);
  current = (current + dir + total) % total;
  slides.dataset.current = current;
  slides.style.transform = 'translateX(-' + (current * 100) + '%)';
  dots.forEach(function(d, i) { d.classList.toggle('active', i === current); });
  updateDesc(card, current);
}

function goSlide(dot, idx) {
  var slider = dot.closest('.proj-slider');
  var card = slider.closest('.project-card');
  var slides = slider.querySelector('.proj-slides');
  var dots = slider.querySelectorAll('.proj-dot');
  slides.dataset.current = idx;
  slides.style.transform = 'translateX(-' + (idx * 100) + '%)';
  dots.forEach(function(d, i) { d.classList.toggle('active', i === idx); });
  updateDesc(card, idx);
}

// ── LIGHTBOX ─────────────────────────────────────────────────────
var _lbSlider = null;

function openLightbox(slider) {
  _lbSlider = slider;
  _showLightboxSlide(parseInt(slider.querySelector('.proj-slides').dataset.current || 0));
  document.getElementById('proj-lightbox').classList.add('show');
  document.body.style.overflow = 'hidden';
}

function closeLightbox() {
  document.getElementById('proj-lightbox').classList.remove('show');
  document.body.style.overflow = '';
  _lbSlider = null;
}

function lightboxNav(dir) {
  if (!_lbSlider) return;
  var slides = _lbSlider.querySelector('.proj-slides');
  var total = slides.children.length;
  var current = parseInt(slides.dataset.current || 0);
  current = (current + dir + total) % total;
  // sync the card slider too
  slides.dataset.current = current;
  slides.style.transform = 'translateX(-' + (current * 100) + '%)';
  _lbSlider.querySelectorAll('.proj-dot').forEach(function(d,i){d.classList.toggle('active',i===current);});
  updateDesc(_lbSlider.closest('.project-card'), current);
  _showLightboxSlide(current);
}

function _showLightboxSlide(idx) {
  var slides = _lbSlider.querySelector('.proj-slides');
  var total = slides.children.length;
  var slide = slides.children[idx];
  var lbImg = document.getElementById('proj-lightbox-img');
  var lbPh  = document.getElementById('proj-lightbox-placeholder');
  var lbIcon = document.getElementById('lb-icon');
  if (slide.tagName === 'IMG') {
    lbImg.src = slide.src;
    lbImg.style.display = 'block';
    lbPh.style.display = 'none';
  } else {
    lbImg.style.display = 'none';
    lbPh.style.display = 'flex';
    var icon = slide.querySelector('span');
    lbIcon.textContent = icon ? icon.textContent : '🖼️';
  }
  document.getElementById('proj-lightbox-counter').textContent = (idx+1) + ' / ' + total;
}

// close on backdrop click & keyboard — wait for DOM
document.addEventListener('DOMContentLoaded', function() {
  document.getElementById('proj-lightbox').addEventListener('click', function(e){
    if (e.target === this) closeLightbox();
  });

  document.addEventListener('keydown', function(e){
    if (e.key === 'Escape') closeLightbox();
    if (e.key === 'ArrowRight') lightboxNav(1);
    if (e.key === 'ArrowLeft') lightboxNav(-1);
  });

  document.querySelectorAll('.proj-slider').forEach(function(slider) {
    slider.addEventListener('click', function(e) {
      if (!e.target.classList.contains('proj-btn') && !e.target.classList.contains('proj-dot')) {
        openLightbox(slider);
      }
    });
    var startX = 0;
    slider.addEventListener('touchstart', function(e) { startX = e.touches[0].clientX; }, {passive:true});
    slider.addEventListener('touchend', function(e) {
      var diff = startX - e.changedTouches[0].clientX;
      if (Math.abs(diff) > 40) {
        var btn = slider.querySelector(diff > 0 ? '.next' : '.prev');
        if (btn) slideProj(btn, diff > 0 ? 1 : -1);
      }
    });
  });
});





