// ── SCROLL-TRIGGERED REVEAL ANIMATIONS ──────────────────────────────
(function(){
  // Elements to reveal
  var selectors = [
    '.service-card',
    '.mv-card',
    '.project-card',
    '.about-card',
    '.branch-card',
    '.contact-item',
    '.mv-pillar',
    '.info-row',
    '.footer-col',
    '.section-label',
    '.section-title',
    '.divider'
  ];

  var allEls = document.querySelectorAll(selectors.join(','));

  allEls.forEach(function(el, i) {
    el.classList.add('sr-hidden');
    // Stagger siblings within the same parent
    var siblings = el.parentElement ? el.parentElement.querySelectorAll(el.tagName + '.sr-hidden') : [];
    var sibIndex = Array.prototype.indexOf.call(siblings, el);
    el.style.transitionDelay = (sibIndex * 0.08) + 's';
  });

  var observer = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      if (entry.isIntersecting) {
        entry.target.classList.add('sr-visible');
        observer.unobserve(entry.target); // animate once
      }
    });
  }, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });

  allEls.forEach(function(el) { observer.observe(el); });
})();
  // ── CEO QUOTE: typewriter → cite fade-in → signature draw ──────────
  (function(){
    var quoteEl  = document.getElementById('ceo-quote-text');
    var citeEl   = document.getElementById('ceo-quote-cite');
    var sigWrap  = document.querySelector('.ceo-sig-wrap');
    var svg      = document.getElementById('ceo-sig-svg');
    if (!quoteEl) return;

    // Add blinking cursor keyframe once
    if (!document.getElementById('tw-blink-style')) {
      var ks = document.createElement('style');
      ks.id = 'tw-blink-style';
      ks.textContent = '@keyframes twBlink{0%,100%{opacity:1}50%{opacity:0}}';
      document.head.appendChild(ks);
    }

    var typedOnce = false;
    var sigRunning = false;

    function drawSignature() {
      if (sigRunning) return;
      sigRunning = true;
      if (svg) {
        svg.classList.remove('is-drawing');
        void svg.offsetWidth;
      }
      if (sigWrap) sigWrap.style.opacity = '1';
      setTimeout(function(){
        if (svg) svg.classList.add('is-drawing');
        setTimeout(function(){ sigRunning = false; }, 3500);
      }, 200);
    }

    // Hide cite initially so it types in
    if (citeEl) { citeEl.style.opacity = '0'; citeEl.style.transition = 'none'; }

    function typewrite(el, text, speed, onDone) {
      el.textContent = '';
      var cursor = document.createElement('span');
      cursor.style.cssText = 'display:inline-block;width:2px;height:0.9em;background:currentColor;margin-left:1px;vertical-align:middle;animation:twBlink 0.65s step-end infinite;opacity:0.7;';
      el.appendChild(cursor);
      var i = 0;
      var iv = setInterval(function(){
        if (i < text.length) {
          el.insertBefore(document.createTextNode(text[i]), cursor);
          i++;
        } else {
          clearInterval(iv);
          cursor.remove();
          if (onDone) onDone();
        }
      }, speed);
    }

    function runSequence() {
      if (typedOnce) {
        drawSignature();
        return;
      }
      typedOnce = true;

      var quoteText = quoteEl.textContent;
      var citeText  = citeEl ? citeEl.textContent : '';
      var quoteSpeed = Math.max(6, Math.min(10, Math.round(1000 / quoteText.length)));
      var citeSpeed  = Math.max(14, Math.min(22, Math.round(600 / (citeText.length || 1))));

      // Step 1: typewrite quote
      typewrite(quoteEl, quoteText, quoteSpeed, function(){
        // Step 2: typewrite cite
        if (citeEl) {
          citeEl.style.opacity = '1';
          setTimeout(function(){
            typewrite(citeEl, citeText, citeSpeed, function(){
              // Step 3: draw signature
              setTimeout(drawSignature, 400);
            });
          }, 200);
        } else {
          setTimeout(drawSignature, 600);
        }
      });
    }

    // Trigger every time quote scrolls into view
    var obs = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if (e.isIntersecting) runSequence();
      });
    }, { threshold: 0.4 });

    obs.observe(quoteEl);
  })();

// ── HERO TITLE TYPEWRITER + STAT COUNT-UP ───────────────────────
(function(){
  var titleEl = document.getElementById('hero-title');
  if (!titleEl) return;

  // Blink keyframe (reuse if already added by CEO quote)
  if (!document.getElementById('tw-blink-style')) {
    var ks = document.createElement('style');
    ks.id = 'tw-blink-style';
    ks.textContent = '@keyframes twBlink{0%,100%{opacity:1}50%{opacity:0}}';
    document.head.appendChild(ks);
  }

  // Hide title immediately so original text never shows
  titleEl.style.visibility = 'hidden';
  titleEl.innerHTML = '';

  // Stat entries: {el, endVal, suffix, isString}
  var statNums = document.querySelectorAll('.stat-num');
  var stats = [
    { suffix: '+', end: 5, str: null },
    { suffix: '',  end: 5, str: null },
    { suffix: '%', end: 100, str: null },
    { suffix: '',  end: null, str: '24/7' }
  ];

  // Hide stat numbers initially
  statNums.forEach(function(el) { el.textContent = ''; });

  function addCursor(el) {
    var c = document.createElement('span');
    c.className = 'tw-cursor';
    c.style.cssText = 'display:inline-block;width:2px;height:0.85em;background:currentColor;margin-left:1px;vertical-align:middle;animation:twBlink 0.6s step-end infinite;opacity:0.75;';
    el.appendChild(c);
    return c;
  }

  function typeText(el, text, speed, done) {
    var i = 0;
    var cur = addCursor(el);
    var iv = setInterval(function(){
      if (i < text.length) {
        el.insertBefore(document.createTextNode(text[i]), cur);
        i++;
      } else {
        clearInterval(iv);
        cur.remove();
        if (done) done();
      }
    }, speed);
  }

  function countUp(el, end, suffix, delay, done) {
    setTimeout(function(){
      var start = 0;
      var duration = Math.min(3000, end * 80 + 600);
      var step = Math.ceil(duration / end);
      var iv = setInterval(function(){
        start++;
        el.textContent = start + suffix;
        if (start >= end) {
          clearInterval(iv);
          if (done) done();
        }
      }, step);
    }, delay);
  }

  function typeString(el, str, delay, done) {
    setTimeout(function(){
      typeText(el, str, 200, done);
    }, delay);
  }

  function animateStats() {
    var delay = 0;
    var stagger = 500;
    statNums.forEach(function(el, i) {
      var cfg = stats[i];
      if (!cfg) return;
      (function(elem, cfg, d){
        if (cfg.str) {
          typeString(elem, cfg.str, d, null);
        } else {
          countUp(elem, cfg.end, cfg.suffix, d, null);
        }
      })(el, cfg, delay);
      delay += stagger;
    });
  }

  setTimeout(function(){
    titleEl.style.visibility = 'visible';
    var line1 = 'Precision Surveys.';
    var line2 = 'Engineering Excellence.';

    typeText(titleEl, line1, 95, function(){
      titleEl.appendChild(document.createElement('br'));
      var em = document.createElement('em');
      titleEl.appendChild(em);
      typeText(em, line2, 88, function(){
        setTimeout(animateStats, 400);
      });
    });
  }, 3600);
})();

// ── NAV SHRINK ON SCROLL ─────────────────────────────────────────
(function(){
  var nav = document.querySelector('nav');
  if (!nav) return;
  window.addEventListener('scroll', function(){
    if (window.scrollY > 60) {
      nav.classList.add('nav-scrolled');
    } else {
      nav.classList.remove('nav-scrolled');
    }
  }, { passive: true });
})();

// ── PARALLAX HERO BACKGROUND ─────────────────────────────────────
(function(){
  var heroBg = document.querySelector('.hero-bg');
  var heroGrid = document.querySelector('.hero-grid-lines');
  if (!heroBg) return;
  // Disable on mobile (performance)
  if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
  window.addEventListener('scroll', function(){
    var y = window.scrollY;
    if (y > window.innerHeight) return;
    var offset = y * 0.35;
    heroBg.style.transform = 'translateY(' + offset + 'px)';
    if (heroGrid) heroGrid.style.transform = 'translateY(' + (offset * 0.6) + 'px)';
  }, { passive: true });
})();

// ── UPGRADE STAGGER DELAYS FOR PREMIUM FEEL ──────────────────────
(function(){
  // Re-apply tighter, more intentional stagger per row
  var groups = [
    '.service-card', '.mv-card', '.project-card',
    '.about-card', '.branch-card'
  ];
  groups.forEach(function(sel){
    var els = document.querySelectorAll(sel + '.sr-hidden');
    var perRow = sel === '.service-card' ? 3 : 2;
    els.forEach(function(el, i){
      var row = Math.floor(i / perRow);
      var col = i % perRow;
      // Row staggers by 120ms, column by 100ms within row
      el.style.transitionDelay = (row * 0.12 + col * 0.10) + 's';
    });
  });
})();
